import java.util.ArrayList;import java.util.LinkedHashMap;import java.util.List;import java.util.Map;import java.util.TreeMap;
final class CommandPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}static final class RouteTable{final Map<String,String>routes;RouteTable(Map<String,String>v){routes=new TreeMap<>(v);}}interface Command{void execute();void undo();}
static final class SetRoute implements Command{private final RouteTable receiver;private final String key,value;private String previous;private boolean existed;SetRoute(RouteTable r,String k,String v){receiver=r;key=k;value=v;}public void execute(){existed=receiver.routes.containsKey(key);previous=receiver.routes.get(key);receiver.routes.put(key,value);}public void undo(){if(existed)receiver.routes.put(key,previous);else receiver.routes.remove(key);}}
static final class Invoker{final List<Command>history=new ArrayList<>();void run(Command c){c.execute();history.add(c);}void undo(){if(history.isEmpty())throw new PatternException("no_history");history.remove(history.size()-1).undo();}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Map<String,String>initial=new LinkedHashMap<>();((Map<String,Object>)input.getOrDefault("initial",Map.of())).forEach((k,v)->initial.put(k,String.valueOf(v)));RouteTable table=new RouteTable(initial);Invoker invoker=new Invoker();for(Map<String,Object>v:(List<Map<String,Object>>)input.getOrDefault("commands",List.of()))invoker.run(new SetRoute(table,String.valueOf(v.get("key")),String.valueOf(v.get("value"))));for(int i=0;i<((Number)input.getOrDefault("undo",0)).intValue();i++)invoker.undo();return Map.of("routes",table.routes,"history",invoker.history.size());}}
